from flask import Flask, request, jsonify
import prometheus_client

app = Flask(__name__)

# Metrics to expose
counter_users = prometheus_client.Counter(
    'users', 'Number of users'
)
gauge_requests = prometheus_client.Gauge(
    'requests', 'Current number of requests'
)

@app.route('/metrics')
def metrics():
    return jsonify(prometheus_client.generate_latest())

@app.before_request
def log_request_data():
    user_id = request.headers.get('X-User-ID')
    api_key = request.headers.get('X-API-Key')

    # Add request body data to metrics if available
    request_body_metrics = {'body': None}
    if request.json:
        counter_users.inc()
        gauge_requests.inc()

        for key, value in request.json.items():
            request_body_metrics[key] = value

    elif request.form:
        counter_users.inc()
        gauge_requests.inc()

        for key, value in request.form.items():
            request_body_metrics[key] = value
    else:
        request_body_metrics['body'] = 'no body data available'

    if user_id and api_key:
        prometheus_client.gauge('user_request', f"User ID: {user_id}, API Key: {api_key}", request_body_metrics)

if __name__ == '__main__':
    app.run(debug=True)